import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { EXAM_DATE, AL_STREAMS } from './constants';
import { TimeLeft, Subject, User } from './types';
import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import StudyGoals from './components/StudyGoals';
import ExamNews from './components/ExamNews';
import LoginPage from './components/LoginPage';
import FocusTimer from './components/FocusTimer';
import ResourceVault from './components/ResourceVault';
import AIChatBuddy from './components/AIChatBuddy';
import CurriculumHub from './components/CurriculumHub';
import CreditsPage from './components/CreditsPage';
import TimetablePage from './components/TimetablePage';
import { fetchLatestExamNews, ExamNews as ExamNewsType } from './services/geminiService';

type View = 'dashboard' | 'curriculum' | 'tools' | 'chat' | 'timetable' | 'credits';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState<View>('dashboard');
  const [currentExamDate, setCurrentExamDate] = useState<Date>(EXAM_DATE);
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [news, setNews] = useState<ExamNewsType | null>(null);
  const [lastNewsUpdate, setLastNewsUpdate] = useState<string | null>(null);
  const [isLoadingNews, setIsLoadingNews] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [subjects, setSubjects] = useState<Subject[]>([]);

  const greeting = useMemo(() => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good Morning";
    if (hour < 17) return "Good Afternoon";
    return "Good Evening";
  }, []);

  const batchIndex = useMemo(() => {
    if (subjects.length === 0) return 0;
    const total = subjects.reduce((acc, s) => acc + s.progress, 0);
    return Math.round(total / subjects.length);
  }, [subjects]);

  useEffect(() => {
    const savedUser = localStorage.getItem('al_2026_user');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);

      const savedSubjects = localStorage.getItem(`al_2026_subjects_${parsedUser.streamId}`);
      if (savedSubjects) {
        setSubjects(JSON.parse(savedSubjects));
      } else {
        const defaultStream = AL_STREAMS.find(s => s.id === parsedUser.streamId) || AL_STREAMS[0];
        setSubjects(defaultStream.subjects);
      }
    }
    setIsAuthLoading(false);
  }, []);

  useEffect(() => {
    if (user && subjects.length > 0) {
      localStorage.setItem(`al_2026_subjects_${user.streamId}`, JSON.stringify(subjects));
    }
  }, [subjects, user]);

  const handleLogin = (name: string, remember: boolean, streamId: string) => {
    const newUser = { name, isLoggedIn: true, streamId };
    setUser(newUser);
    if (remember) localStorage.setItem('al_2026_user', JSON.stringify(newUser));
    const stream = AL_STREAMS.find(s => s.id === streamId) || AL_STREAMS[0];
    setSubjects(stream.subjects);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('al_2026_user');
    setSubjects([]);
  };

  const toggleUnit = (subjectId: string, unitId: string) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === subjectId) {
        const newUnits = s.units.map(u => 
          u.id === unitId ? { ...u, completed: !u.completed } : u
        );
        const completedCount = newUnits.filter(u => u.completed).length;
        const newProgress = Math.round((completedCount / newUnits.length) * 100);
        return { ...s, units: newUnits, progress: newProgress };
      }
      return s;
    }));
  };

  const togglePriority = (subjectId: string) => {
    setSubjects(prev => prev.map(s => 
      s.id === subjectId ? { ...s, isPrioritized: !s.isPrioritized } : s
    ));
  };

  const calculateTimeLeft = useCallback(() => {
    const now = new Date();
    const difference = currentExamDate.getTime() - now.getTime();
    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    } else {
      setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
    }
  }, [currentExamDate]);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const refreshNews = async () => {
    setIsLoadingNews(true);
    try {
      const newsResult = await fetchLatestExamNews();
      setNews(newsResult);
      setLastNewsUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

  useEffect(() => {
    if (user && timeLeft.days > 0) {
      refreshNews();
    }
  }, [user, timeLeft.days]);

  if (isAuthLoading) return <div className="min-h-screen bg-slate-950 flex items-center justify-center"><div className="w-12 h-12 rounded-2xl border-2 border-blue-500/20 border-t-blue-500 animate-spin" /></div>;
  if (!user) return <LoginPage onLogin={handleLogin} />;

  const renderView = () => {
    switch(activeView) {
      case 'dashboard':
        return (
          <div className="grid md:grid-cols-12 gap-6 md:gap-8 animate-reveal">
            <div className="md:col-span-8 space-y-8">
              <section className="relative p-8 md:p-12 glass-card rounded-[3rem] overflow-hidden">
                {/* Decorative glows */}
                <div className="absolute -top-24 -left-24 w-64 h-64 bg-blue-500/10 blur-[100px] rounded-full" />
                <div className="absolute -bottom-24 -right-24 w-64 h-64 bg-indigo-500/10 blur-[100px] rounded-full" />

                <div className="relative z-10 flex flex-col items-center text-center">
                  <div className="mb-6 px-4 py-1.5 rounded-full bg-white/5 border border-white/10 backdrop-blur-md">
                    <span className="text-xs font-bold font-outfit text-blue-300 uppercase tracking-widest">
                      ✨ {timeLeft.days > 365 ? 'The journey begins' : 'Success is built daily'}
                    </span>
                  </div>
                  <h1 className="text-4xl md:text-6xl font-black font-outfit mb-4 text-white tracking-tight leading-tight">
                    {greeting}, <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-indigo-400">{user.name.split(' ')[0]}.</span>
                  </h1>
                  <p className="text-slate-400 text-sm md:text-lg max-w-lg mb-12 font-medium">
                    Your focus is your greatest asset. Keep pushing for that 3A target.
                  </p>
                  <CountdownCard timeLeft={timeLeft} />
                </div>
              </section>
              <ExamNews news={news} isLoading={isLoadingNews} onRefresh={refreshNews} lastUpdated={lastNewsUpdate} />
            </div>

            <div className="md:col-span-4 space-y-6">
              <div className="glass-card rounded-[2.5rem] p-8 relative overflow-hidden group">
                <div className="absolute inset-0 bg-gradient-to-br from-emerald-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
                <div className="relative z-10">
                  <div className="flex justify-between items-center mb-6">
                    <h4 className="font-black text-xs uppercase tracking-widest text-emerald-400">Mastery Index</h4>
                    <span className="text-[10px] font-bold text-slate-500 uppercase">2026 Cycle</span>
                  </div>
                  <div className="flex items-baseline gap-2 mb-4">
                    <span className="text-5xl font-black font-mono-tech text-white leading-none">{batchIndex}%</span>
                    <span className="text-xs font-bold text-slate-500 uppercase tracking-tighter">Overall</span>
                  </div>
                  <div className="w-full h-2 bg-slate-900/50 rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-gradient-to-r from-emerald-600 to-cyan-400 rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(16,185,129,0.3)]" style={{ width: `${batchIndex}%` }} />
                  </div>
                </div>
              </div>
              <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
              <StudyGoals />
            </div>
          </div>
        );
      case 'curriculum':
        return (
          <div className="grid md:grid-cols-12 gap-8 animate-reveal">
            <div className="md:col-span-8">
              <CurriculumHub subjects={subjects} toggleUnit={toggleUnit} />
            </div>
            <div className="md:col-span-4">
              <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
            </div>
          </div>
        );
      case 'tools':
        return (
          <div className="grid md:grid-cols-12 gap-8 animate-reveal">
            <div className="md:col-span-6">
              <FocusTimer />
            </div>
            <div className="md:col-span-6">
              <ResourceVault />
            </div>
          </div>
        );
      case 'chat':
        return (
          <div className="max-w-4xl mx-auto animate-reveal">
            <AIChatBuddy />
          </div>
        );
      case 'timetable':
        return (
          <div className="animate-reveal">
            <TimetablePage subjects={subjects} />
          </div>
        );
      case 'credits':
        return (
          <div className="max-w-3xl mx-auto animate-reveal">
            <CreditsPage />
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-32">
      <nav className="p-8 md:px-12 flex justify-between items-center max-w-7xl mx-auto">
        <div className="flex items-center gap-4 cursor-pointer group" onClick={() => setActiveView('dashboard')}>
          <div className="w-11 h-11 bg-white/[0.03] border border-white/10 rounded-2xl flex items-center justify-center font-black text-xl text-white shadow-lg group-hover:scale-110 transition-transform">
             <span className="text-transparent bg-clip-text bg-gradient-to-br from-blue-400 to-indigo-500">A</span>
          </div>
          <div className="flex flex-col">
            <span className="text-xl font-black tracking-tight font-outfit uppercase leading-none text-white">HUB 2026</span>
            <span className="text-[9px] text-blue-500/60 font-black tracking-[0.2em] uppercase mt-0.5">Academic Portal</span>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="hidden sm:flex flex-col items-end">
             <span className="text-[9px] font-black uppercase tracking-widest text-slate-500">Signed In</span>
             <span className="text-xs font-bold text-slate-200">{user.name}</span>
          </div>
          <button onClick={handleLogout} className="p-3 rounded-2xl bg-white/5 border border-white/10 text-slate-400 hover:text-red-400 hover:bg-red-500/5 transition-all">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
            </svg>
          </button>
        </div>
      </nav>

      <main className="px-6 md:px-12 max-w-7xl mx-auto pt-2">
        {renderView()}
      </main>

      {/* Floating Navigation */}
      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-50 w-full max-w-xl px-6">
        <div className="p-2 glass-card rounded-[2.5rem] border-white/10 flex items-center justify-between shadow-2xl backdrop-blur-3xl">
          {[
            { id: 'dashboard', label: 'Home', icon: 'M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z' },
            { id: 'curriculum', label: 'Study', icon: 'M9 4.804A7.968 7.968 0 005.5 4c-1.255 0-2.443.29-3.5.804v10A7.969 7.969 0 015.5 14c1.669 0 3.218.51 4.5 1.385A7.962 7.962 0 0114.5 14c1.255 0 2.443.29 3.5.804v-10A7.968 7.968 0 0014.5 4c-1.255 0-2.443.29-3.5.804V12a1 1 0 11-2 0V4.804z' },
            { id: 'timetable', label: 'Plan', icon: 'M6 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-1V3a1 1 0 10-2 0v1H7V3a1 1 0 00-1-1zm0 5a1 1 0 000 2h8a1 1 0 100-2H6z' },
            { id: 'tools', label: 'Zen', icon: 'M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z' },
            { id: 'chat', label: 'Buddy', icon: 'M18 10c0 3.866-3.582 7-8 7a8.841 8.841 0 01-4.083-.98L2 17l1.338-3.123C2.493 12.767 2 11.434 2 10c0-3.866 3.582-7 8-7s8 3.134 8 7zM7 9H5v2h2V9zm8 0h-2v2h2V9zM9 9h2v2H9V9z' }
          ].map((item) => (
            <button 
              key={item.id}
              onClick={() => setActiveView(item.id as View)}
              className={`flex-1 py-4 flex flex-col items-center gap-1 transition-all rounded-[2rem] ${activeView === item.id ? 'nav-button-active text-white' : 'text-slate-500 hover:text-slate-300'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d={item.icon} />
              </svg>
              <span className="text-[9px] font-black uppercase tracking-widest">{item.label}</span>
