          ))}
        </div>
      </div>

      <footer className="mt-24 py-12 text-center">
        <div className="inline-flex items-center gap-2 px-6 py-2 rounded-full bg-white/5 border border-white/10 opacity-40 hover:opacity-100 transition-opacity">
