import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithStudyBuddy } from '../services/geminiService';

const AIChatBuddy: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping, error]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    setError(null);
    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);

    try {
      const response = await chatWithStudyBuddy([...messages, userMsg], currentInput);
      const botMsg: ChatMessage = { role: 'model', text: response, timestamp: Date.now() };
      setMessages(prev => [...prev, botMsg]);
    } catch (err: any) {
      setError("Failed to get a response. Please try again.");
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="glass-card rounded-[3rem] p-8 md:p-10 border-indigo-500/10 flex flex-col h-[calc(100vh-280px)] min-h-[550px] shadow-2xl">
      <div className="flex items-center justify-between mb-8 border-b border-white/5 pb-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-indigo-500/20 to-purple-500/20 border border-indigo-500/20 flex items-center justify-center text-xl shadow-inner">
            🤖
          </div>
          <div>
            <h3 className="font-black text-sm uppercase tracking-widest text-white">Study Buddy AI</h3>
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-tighter mt-0.5">Online & Ready to Help</p>
          </div>
        </div>
        <div className={`flex items-center gap-2 px-3 py-1 rounded-full bg-slate-900/50 border border-white/5`}>
          <div className={`w-1.5 h-1.5 rounded-full ${error ? 'bg-red-500' : 'bg-emerald-500'} animate-pulse`} />
          <span className="text-[8px] font-black uppercase text-slate-500">{error ? 'System Error' : 'Neural Link Active'}</span>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-6 mb-8 px-2">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center py-10 opacity-60">
            <div className="w-20 h-20 bg-white/[0.02] border border-white/5 rounded-[2.5rem] flex items-center justify-center text-3xl mb-8">✨</div>
            <h4 className="text-lg font-black font-outfit text-white mb-2">Hello, Candidate.</h4>
            <p className="text-slate-500 text-sm max-w-xs mx-auto font-medium">
              I'm your dedicated 2026 Academic Assistant. Ask me anything about your syllabus or study habits.
            </p>
          </div>
        )}

        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-reveal`}>
            <div className={`max-w-[80%] p-5 rounded-[1.8rem] text-sm leading-relaxed ${
              msg.role === 'user' 
                ? 'bg-blue-600 text-white rounded-tr-none shadow-lg shadow-blue-900/20' 
                : 'bg-white/[0.03] text-slate-200 border border-white/10 rounded-tl-none backdrop-blur-sm'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start animate-reveal">
            <div className="bg-white/[0.03] p-5 rounded-[1.8rem] rounded-tl-none flex gap-1.5 border border-white/10">
              <span className="w-1.5 h-1.5 bg-indigo-500/40 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <span className="w-1.5 h-1.5 bg-indigo-500/40 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
              <span className="w-1.5 h-1.5 bg-indigo-500/40 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
          </div>
        )}

        {error && (
          <div className="flex justify-center">
            <div className="bg-red-500/5 border border-red-500/20 text-red-400 text-[10px] font-black uppercase px-6 py-2.5 rounded-full shadow-xl">
              {error}
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="relative">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type a message or ask a question..."
            className="w-full bg-white/[0.02] border border-white/10 rounded-3xl px-7 py-5 text-sm text-white placeholder-slate-600 focus:outline-none focus:border-indigo-500 focus:bg-white/[0.04] transition-all pr-16 shadow-inner"
          />
          <button 
            type="submit"
