export const fetchLatestExamNews = async (): Promise<ExamNews> => {
  return withRetry(async () => {
    try {
      const ai = getAIClient();
      // Using gemini-3-flash-preview for faster news retrieval on Vercel
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "Find the latest updates on the Sri Lanka GCE A/L 2026 examination dates, official timetables, and registration news from doenets.lk or official government sources. Summarize clearly.",
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = groundingChunks
        .map((chunk: any) => ({
          uri: chunk.web?.uri || chunk.web?.url,
          title: chunk.web?.title || "Official Source"
        }))
        .filter((s: any) => s.uri && s.title) || [];

      const text = response.text || "";
      const lowerText = text.toLowerCase();

      // Heuristic to check for official confirmation status
      const isConfirmed = (lowerText.includes("2026") && 
                          (lowerText.includes("officially announced") || 
                           lowerText.includes("confirmed") || 
                           lowerText.includes("timetable released")));

      return {
        text: text || "Scanning complete. No specific dates found for 2026 yet, but keep checking here for live updates.",
        sources: sources.slice(0, 5),
        isConfirmed
      };
    } catch (error: any) {
      console.error("Exam News Error:", error);
      if (error.message === "API_KEY_MISSING") {
        return {
          text: "News feed offline: API Key not configured on Vercel.",
          sources: [],
          isConfirmed: false,
          error: "Missing API Key"
        };
      }
      return {
        text: "We encountered an issue while scanning official news sources. Please visit doenets.lk directly for verified updates.",
        sources: [{ uri: "https://www.doenets.lk", title: "Department of Examinations Sri Lanka" }],
        isConfirmed: false,
        error: error.message
      };
    }
  });
};

