            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 110 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-1.392-2.348 1 1 0 111.885-.666 5.002 5.002 0 005.999-1.935H11z" clipRule="evenodd" />
              </svg>
            </button>
            <button 
              onClick={toggleTimer}
              className={`w-20 h-20 rounded-3xl flex items-center justify-center text-white shadow-2xl transition-all active:scale-90 ${isActive ? 'bg-slate-800' : mode === 'work' ? 'bg-cyan-600 shadow-cyan-900/20' : 'bg-emerald-600 shadow-emerald-900/20'}`}
            >
              {isActive ? (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 ml-1" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                </svg>
              )}
            </button>
            <div className="w-12 h-12" /> {/* Spacer for symmetry */}
          </div>

          <div className="w-full bg-slate-950/40 rounded-3xl p-6 border border-white/5">
            <div className="flex items-center justify-between mb-6">
              <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Currently Focusing</span>
                <span className="text-xs font-bold text-slate-200 mt-0.5">{activePlaylist.icon} {currentTrack.name}</span>
              </div>
              <div className="flex items-center gap-3">
                <button onClick={prevTrack} className="text-slate-500 hover:text-white transition-colors">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M8.445 14.832A1 1 0 0010 14v-2.798l5.445 3.63A1 1 0 0017 14V6a1 1 0 00-1.555-.832L10 8.798V6a1 1 0 00-1.555-.832l-6 4a1 1 0 000 1.664l6 4z" /></svg>
                </button>
                <button 
                  onClick={toggleMusic}
                  className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isMusicPlaying ? 'bg-cyan-500 text-white' : 'bg-white/5 text-slate-400 hover:text-white'}`}
                >
                  {isMusicPlaying ? (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                  ) : (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 ml-0.5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                  )}
                </button>
                <button onClick={nextTrack} className="text-slate-500 hover:text-white transition-colors">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M4.555 5.168A1 1 0 003 6v8a1 1 0 001.555.832L10 11.202V14a1 1 0 001.555.832l6-4a1 1 0 000-1.664l-6-4A1 1 0 0010 6v2.798l-5.445-3.63z" /></svg>
                </button>
              </div>
            </div>

            <div className="grid grid-cols-4 gap-2 mb-6">
              {PLAYLISTS.map(p => (
                <button 
                  key={p.id}
                  onClick={() => selectPlaylist(p.id)}
                  className={`flex flex-col items-center gap-2 p-3 rounded-2xl border transition-all ${activePlaylistId === p.id ? 'bg-cyan-500/10 border-cyan-500/30' : 'bg-black/20 border-white/5 hover:border-white/10'}`}
                >
                  <span className="text-lg">{p.icon}</span>
                  <span className={`text-[8px] font-black uppercase tracking-tighter ${activePlaylistId === p.id ? 'text-cyan-400' : 'text-slate-500'}`}>{p.label.split(' ')[0]}</span>
                </button>
              ))}
            </div>

            <div className="flex items-center gap-4 px-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-slate-500" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.987 3.987 0 0013 10a3.987 3.987 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" /></svg>
              <input 
                type="range" 
                min="0" 
                max="1" 
                step="0.01" 
                value={volume}
                onChange={(e) => setVolume(parseFloat(e.target.value))}
                className="flex-1 h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-cyan-500"
              />
            </div>
            {audioError && <p className="text-[8px] text-red-400 mt-2 text-center uppercase font-black tracking-widest">{audioError}</p>}
          </div>
        </div>
      )}

      {/* Audio Engine */}
      <audio 
        ref={audioRef} 
        src={currentTrack.url}
        onEnded={nextTrack}
        loop={false}
      />
    </div>
  );
};

export default FocusTimer;

import React, { useState, useEffect, useRef } from 'react';

const PLAYLISTS = [
  {
    id: 'lofi',
    label: 'Lo-Fi Chill',
