    ]
  },
  {
    id: 'classical',
    label: 'Classical',
    icon: '🎻',
    tracks: [
      { name: 'Nocturne in Eb', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3' },
      { name: 'Piano Sonata', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-9.mp3' }
    ]
  },
  {
    id: 'nature',
    label: 'Nature',
    icon: '🍃',
    tracks: [
      { name: 'Forest Rain', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3' },
      { name: 'Ocean Mist', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-10.mp3' }
    ]
  },
  {
    id: 'ambient',
    label: 'Deep Zen',
    icon: '🌌',
    tracks: [
      { name: 'Ethereal Space', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-4.mp3' },
      { name: 'Binaural Flow', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-13.mp3' }
    ]
  }
];

const STORAGE_KEY = 'al_2026_focus_settings';

const FocusTimer: React.FC = () => {
  // Load initial settings from localStorage
  const loadSettings = () => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {
      console.error("Failed to load focus settings", e);
    }
    return {
      workMinutes: 25,
      breakMinutes: 5,
      activePlaylistId: PLAYLISTS[0].id,
      volume: 0.4
    };
  };

  const initialSettings = loadSettings();

  const [workMinutes, setWorkMinutes] = useState(initialSettings.workMinutes);
  const [breakMinutes, setBreakMinutes] = useState(initialSettings.breakMinutes);
  const [timeLeft, setTimeLeft] = useState(initialSettings.workMinutes * 60);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'work' | 'break'>('work');
  const [showSettings, setShowSettings] = useState(false);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);

  const [activePlaylistId, setActivePlaylistId] = useState(initialSettings.activePlaylistId);
  const [currentTrackIndex, setCurrentTrackIndex] = useState(0);

  const [volume, setVolume] = useState(initialSettings.volume);
  const [audioError, setAudioError] = useState<string | null>(null);

  const timerRef = useRef<number | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const activePlaylist = PLAYLISTS.find(p => p.id === activePlaylistId) || PLAYLISTS[0];
  const currentTrack = activePlaylist.tracks[currentTrackIndex];

  // Sync settings to localStorage whenever they change
  useEffect(() => {
    const settings = {
      workMinutes,
      breakMinutes,
      activePlaylistId,
      volume
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
  }, [workMinutes, breakMinutes, activePlaylistId, volume]);

  useEffect(() => {
    if (!isActive) {
      setTimeLeft(mode === 'work' ? workMinutes * 60 : breakMinutes * 60);
    }
  }, [workMinutes, breakMinutes, mode]);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      timerRef.current = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      handleComplete();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isActive, timeLeft]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  const handleComplete = () => {
    setIsActive(false);
    if (mode === 'work') {
      setMode('break');
      setTimeLeft(breakMinutes * 60);
    } else {
      setMode('work');
      setTimeLeft(workMinutes * 60);
    }
    // Notification logic could be added here
    if (Notification.permission === 'granted') {
      new Notification(mode === 'work' ? 'Time for a break!' : 'Back to work!', {
        body: mode === 'work' ? 'Great focus session. Rest up!' : 'Let\'s crush the next target.',
        icon: '/favicon.ico'
      });
    }
  };

  const toggleTimer = () => setIsActive(!isActive);

  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? workMinutes * 60 : breakMinutes * 60);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const adjustMinutes = (type: 'work' | 'break', amount: number) => {
    if (type === 'work') {
      setWorkMinutes(prev => Math.max(1, Math.min(120, prev + amount)));
    } else {
      setBreakMinutes(prev => Math.max(1, Math.min(60, prev + amount)));
    }
  };

  const toggleMusic = () => {
    if (isMusicPlaying) {
      audioRef.current?.pause();
      setIsMusicPlaying(false);
    } else {
      setAudioError(null);
      audioRef.current?.play().then(() => {
        setIsMusicPlaying(true);
      }).catch(err => {
        console.error("Audio playback error:", err);
        setAudioError("Playback blocked. Please click play again.");
        setIsMusicPlaying(false);
      });
    }
  };

  const selectPlaylist = (playlistId: string) => {
    const wasPlaying = isMusicPlaying;
    setActivePlaylistId(playlistId);
    setCurrentTrackIndex(0);
    setAudioError(null);

    // Smooth transition
    if (wasPlaying) {
      setTimeout(() => {
        audioRef.current?.play().catch(() => setIsMusicPlaying(false));
      }, 50);
    }
  };

  const nextTrack = () => {
    setCurrentTrackIndex((prev) => (prev + 1) % activePlaylist.tracks.length);
  };

  const prevTrack = () => {
    setCurrentTrackIndex((prev) => (prev - 1 + activePlaylist.tracks.length) % activePlaylist.tracks.length);
  };

  return (
    <div className="glass-card rounded-[2.5rem] p-8 border-cyan-500/10 w-full relative overflow-hidden flex flex-col items-center shadow-2xl h-full">
      {/* Background Zen Decoration */}
      <div className={`absolute top-0 left-0 w-full h-1 transition-colors duration-1000 ${mode === 'work' ? 'bg-cyan-500/40' : 'bg-emerald-500/40'}`} />
      <div className={`absolute -top-24 -right-24 w-64 h-64 blur-[100px] rounded-full opacity-10 transition-colors duration-1000 ${mode === 'work' ? 'bg-cyan-500' : 'bg-emerald-500'}`} />

      <div className="flex justify-between items-center w-full mb-8 relative z-10">
        <div className="flex flex-col">
          <h3 className="text-sm font-black uppercase tracking-widest text-white">Focus Hub</h3>
          <span className={`text-[10px] font-bold uppercase tracking-tighter mt-0.5 ${mode === 'work' ? 'text-cyan-400' : 'text-emerald-400'}`}>
            {mode === 'work' ? 'Deep Work' : 'Refuel Break'}
          </span>
        </div>
        <button 
          onClick={() => setShowSettings(!showSettings)}
          className={`p-2 rounded-xl transition-all ${showSettings ? 'bg-white/10 text-white shadow-inner shadow-black/20' : 'text-slate-500 hover:text-white'}`}
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0a1.532 1.532 0 01-2.286.948c-1.372-.836-2.942.734-2.106 2.106.54.886.061 2.042-.947 2.287-1.561.379-1.561 2.6 0 2.978a1.532 1.532 0 01.947 2.287c-.836 1.372.734 2.942 2.106 2.106a1.532 1.532 0 012.287.947c.379 1.561 2.6 1.561 2.978 0a1.533 1.533 0 012.287-.947c1.372.836 2.942-.734 2.106-2.106a1.533 1.533 0 01.947-2.287c1.561-.379 1.561-2.6 0-2.978a1.532 1.532 0 01-.947-2.287c.836-1.372-.734-2.942-2.106-2.106a1.532 1.532 0 01-2.287-.947zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
          </svg>
        </button>
      </div>

      {showSettings ? (
        <div className="w-full space-y-8 py-4 animate-reveal">
          <div className="space-y-6">
            <div className="space-y-3">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Work Cycle (Minutes)</span>
              <div className="flex items-center justify-between bg-black/40 p-2 rounded-2xl border border-white/5">
                <button onClick={() => adjustMinutes('work', -5)} className="w-10 h-10 rounded-xl bg-slate-800 text-white hover:bg-slate-700 transition-colors shadow-lg active:scale-95 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" /></svg>
                </button>
                <span className="text-2xl font-black font-mono-tech text-white w-12 text-center">{workMinutes}</span>
                <button onClick={() => adjustMinutes('work', 5)} className="w-10 h-10 rounded-xl bg-slate-800 text-white hover:bg-slate-700 transition-colors shadow-lg active:scale-95 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>
                </button>
              </div>
            </div>
            <div className="space-y-3">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Break Duration (Minutes)</span>
              <div className="flex items-center justify-between bg-black/40 p-2 rounded-2xl border border-white/5">
                <button onClick={() => adjustMinutes('break', -1)} className="w-10 h-10 rounded-xl bg-slate-800 text-white hover:bg-slate-700 transition-colors shadow-lg active:scale-95 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" /></svg>
                </button>
                <span className="text-2xl font-black font-mono-tech text-white w-12 text-center">{breakMinutes}</span>
                <button onClick={() => adjustMinutes('break', 1)} className="w-10 h-10 rounded-xl bg-slate-800 text-white hover:bg-slate-700 transition-colors shadow-lg active:scale-95 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011 1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>
                </button>
              </div>
            </div>
          </div>
          <button 
            onClick={() => setShowSettings(false)}
            className="w-full py-4 bg-cyan-600/10 text-cyan-400 border border-cyan-500/20 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-cyan-600 hover:text-white transition-all shadow-xl shadow-cyan-950/20"
          >
            Save Settings
          </button>
        </div>
      ) : (
        <div className="flex flex-col items-center py-6 w-full animate-reveal flex-1">
          <div className="relative mb-12">
            <svg className="w-64 h-64 -rotate-90">
              <circle cx="128" cy="128" r="120" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-slate-900" />
              <circle 
                cx="128" cy="128" r="120" 
                stroke="currentColor" strokeWidth="4" 
                fill="transparent" 
                strokeDasharray={2 * Math.PI * 120}
                strokeDashoffset={2 * Math.PI * 120 * (1 - timeLeft / (mode === 'work' ? workMinutes * 60 : breakMinutes * 60))}
                className={`transition-all duration-1000 ease-linear ${mode === 'work' ? 'text-cyan-500' : 'text-emerald-500'}`}
                strokeLinecap="round"
              />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-6xl font-black font-mono-tech text-white tracking-tighter drop-shadow-[0_0_20px_rgba(255,255,255,0.1)]">{formatTime(timeLeft)}</span>
              <span className={`text-[10px] font-black uppercase tracking-[0.3em] mt-3 ${mode === 'work' ? 'text-cyan-400' : 'text-emerald-400'}`}>
                {mode}ING
              </span>
            </div>
          </div>

          <div className="flex items-center gap-8 mb-12">
            <button 
              onClick={resetTimer}
              className="w-12 h-12 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center text-slate-500 hover:text-white transition-all active:scale-95 group"
              title="Reset Timer"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 group-hover:rotate-[-45deg] transition-transform" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 110 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-1.392-2.348 1 1 0 111.885-.666 5.002 5.002 0 005.999-1.935H11z" clipRule="evenodd" />
              </svg>
            </button>
            <button 
              onClick={toggleTimer}
              className={`w-24 h-24 rounded-[2.5rem] flex items-center justify-center text-white shadow-2xl transition-all active:scale-90 ${isActive ? 'bg-slate-800' : mode === 'work' ? 'bg-cyan-600 shadow-cyan-900/30' : 'bg-emerald-600 shadow-emerald-900/30'}`}
            >
              {isActive ? (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 ml-1.5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                </svg>
              )}
            </button>
            <div className="w-12 h-12" /> {/* Layout Spacer */}
          </div>

          <div className="w-full bg-slate-950/40 rounded-[2rem] p-6 border border-white/5 mt-auto">
            <div className="flex items-center justify-between mb-6">
              <div className="flex flex-col overflow-hidden max-w-[150px]">
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Curated Flow</span>
                <span className="text-xs font-bold text-slate-200 mt-1 truncate">{activePlaylist.icon} {currentTrack.name}</span>
              </div>
              <div className="flex items-center gap-3">
                <button onClick={prevTrack} className="text-slate-500 hover:text-white transition-colors active:scale-90">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M8.445 14.832A1 1 0 0010 14v-2.798l5.445 3.63A1 1 0 0017 14V6a1 1 0 00-1.555-.832L10 8.798V6a1 1 0 00-1.555-.832l-6 4a1 1 0 000 1.664l6 4z" /></svg>
                </button>
                <button 
                  onClick={toggleMusic}
                  className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shadow-xl ${isMusicPlaying ? 'bg-cyan-500 text-white shadow-cyan-900/20' : 'bg-white/5 text-slate-400 hover:text-white'}`}
                >
                  {isMusicPlaying ? (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                  ) : (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 ml-0.5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                  )}
                </button>
                <button onClick={nextTrack} className="text-slate-500 hover:text-white transition-colors active:scale-90">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M4.555 5.168A1 1 0 003 6v8a1 1 0 001.555.832L10 11.202V14a1 1 0 001.555.832l6-4a1 1 0 000-1.664l-6-4A1 1 0 0010 6v2.798l-5.445-3.63z" /></svg>
                </button>
              </div>
            </div>

            <div className="grid grid-cols-4 gap-2 mb-6">
              {PLAYLISTS.map(p => (
                <button 
                  key={p.id}
                  onClick={() => selectPlaylist(p.id)}
                  className={`flex flex-col items-center gap-1.5 p-3 rounded-2xl border transition-all ${activePlaylistId === p.id ? 'bg-cyan-500/10 border-cyan-500/40 shadow-inner' : 'bg-black/20 border-white/5 hover:border-white/10 hover:bg-black/40'}`}
                >
                  <span className="text-xl">{p.icon}</span>
                  <span className={`text-[8px] font-black uppercase tracking-tighter ${activePlaylistId === p.id ? 'text-cyan-400' : 'text-slate-600'}`}>{p.label.split(' ')[0]}</span>
                </button>
              ))}
            </div>

            <div className="flex items-center gap-4 px-2">
              <div className="text-slate-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.987 3.987 0 0013 10a3.987 3.987 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" /></svg>
              </div>
              <input 
                type="range" 
                min="0" 
                max="1" 
                step="0.01" 
                value={volume}
                onChange={(e) => setVolume(parseFloat(e.target.value))}
                className="flex-1 h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-cyan-500 hover:accent-cyan-400"
              />
            </div>
            {audioError && <p className="text-[9px] text-red-400 mt-4 text-center uppercase font-black tracking-widest animate-shake">{audioError}</p>}
          </div>
        </div>
      )}

      {/* Audio Engine */}
      <audio 
        ref={audioRef} 
        src={currentTrack.url}
        onEnded={nextTrack}
        loop={false}
      />
    </div>
  );
};

export default FocusTimer;

import React, { useState, useEffect, useRef } from 'react';

const PLAYLISTS = [
  {
    id: 'lofi',
    label: 'Lo-Fi Chill',
    icon: '☕',
    tracks: [
      { name: 'Morning Coffee', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3' },
      { name: 'Sunset Vibes', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3' },
      { name: 'Late Night Library', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-16.mp3' }
    ]
  },
  {
    id: 'classical',
    label: 'Classical',
    icon: '🎻',
    tracks: [
      { name: 'Nocturne in Eb', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3' },
      { name: 'Piano Sonata', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-9.mp3' }
    ]
  },
  {
    id: 'nature',
    label: 'Nature',
    icon: '🍃',
    tracks: [
      { name: 'Forest Rain', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3' },
      { name: 'Ocean Mist', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-10.mp3' }
    ]
  },
  {
    id: 'ambient',
    label: 'Deep Zen',
    icon: '🌌',
    tracks: [
      { name: 'Ethereal Space', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-4.mp3' },
      { name: 'Binaural Flow', url: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-13.mp3' }
    ]
  }
];

const STORAGE_KEY = 'al_2026_focus_settings';

const FocusTimer: React.FC = () => {
  const loadSettings = () => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {
      console.error("Failed to load focus settings", e);
    }
    return {
      workMinutes: 25,
      breakMinutes: 5,
      activePlaylistId: PLAYLISTS[0].id,
      volume: 0.4
    };
  };

  const initialSettings = loadSettings();

  const [workMinutes, setWorkMinutes] = useState(initialSettings.workMinutes);
  const [breakMinutes, setBreakMinutes] = useState(initialSettings.breakMinutes);
  const [timeLeft, setTimeLeft] = useState(initialSettings.workMinutes * 60);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'work' | 'break'>('work');
  const [showSettings, setShowSettings] = useState(false);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);

  const [activePlaylistId, setActivePlaylistId] = useState(initialSettings.activePlaylistId);
  const [currentTrackIndex, setCurrentTrackIndex] = useState(0);

  const [volume, setVolume] = useState(initialSettings.volume);
  const [audioError, setAudioError] = useState<string | null>(null);

  const timerRef = useRef<number | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const activePlaylist = PLAYLISTS.find(p => p.id === activePlaylistId) || PLAYLISTS[0];
  const currentTrack = activePlaylist.tracks[currentTrackIndex];

  useEffect(() => {
    const settings = {
      workMinutes,
      breakMinutes,
      activePlaylistId,
      volume
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
  }, [workMinutes, breakMinutes, activePlaylistId, volume]);

  useEffect(() => {
    if (!isActive) {
      setTimeLeft(mode === 'work' ? workMinutes * 60 : breakMinutes * 60);
    }
  }, [workMinutes, breakMinutes, mode]);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      timerRef.current = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      handleComplete();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isActive, timeLeft]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  }, [volume]);

  const handleComplete = () => {
    setIsActive(false);
    if (mode === 'work') {
      setMode('break');
      setTimeLeft(breakMinutes * 60);
    } else {
      setMode('work');
      setTimeLeft(workMinutes * 60);
    }
    if (Notification.permission === 'granted') {
      new Notification(mode === 'work' ? 'Time for a break!' : 'Back to work!', {
        body: mode === 'work' ? 'Great focus session. Rest up!' : 'Let\'s crush the next target.',
        icon: '/favicon.ico'
      });
    }
  };

  const toggleTimer = () => setIsActive(!isActive);

  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? workMinutes * 60 : breakMinutes * 60);
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const adjustMinutes = (type: 'work' | 'break', amount: number) => {
    if (type === 'work') {
      setWorkMinutes(prev => Math.max(1, Math.min(120, prev + amount)));
    } else {
      setBreakMinutes(prev => Math.max(1, Math.min(60, prev + amount)));
    }
  };

  const toggleMusic = () => {
    if (isMusicPlaying) {
      audioRef.current?.pause();
      setIsMusicPlaying(false);
    } else {
      setAudioError(null);
      audioRef.current?.play().then(() => {
        setIsMusicPlaying(true);
      }).catch(err => {
        console.error("Audio playback error:", err);
        setAudioError("Playback blocked. Please click play again.");
        setIsMusicPlaying(false);
      });
    }
  };

  const selectPlaylist = (playlistId: string) => {
    const wasPlaying = isMusicPlaying;
    setActivePlaylistId(playlistId);
    setCurrentTrackIndex(0);
    setAudioError(null);
    if (wasPlaying) {
      setTimeout(() => {
        audioRef.current?.play().catch(() => setIsMusicPlaying(false));
      }, 50);
    }
  };

  const nextTrack = () => {
    setCurrentTrackIndex((prev) => (prev + 1) % activePlaylist.tracks.length);
  };

  const prevTrack = () => {
    setCurrentTrackIndex((prev) => (prev - 1 + activePlaylist.tracks.length) % activePlaylist.tracks.length);
  };

  const radius = 100;
  const strokeWidth = 10;
  const normalizedRadius = radius - strokeWidth / 2;
  const circumference = normalizedRadius * 2 * Math.PI;
  const totalTime = mode === 'work' ? workMinutes * 60 : breakMinutes * 60;
  const strokeDashoffset = circumference - (timeLeft / totalTime) * circumference;

  return (
    <div className="glass-card rounded-[2.5rem] p-8 border-cyan-500/10 w-full relative overflow-hidden flex flex-col items-center shadow-2xl h-full min-h-[600px]">
      <div className={`absolute top-0 left-0 w-full h-1 transition-colors duration-1000 ${mode === 'work' ? 'bg-cyan-500/40' : 'bg-emerald-500/40'}`} />
      <div className={`absolute -top-24 -right-24 w-64 h-64 blur-[100px] rounded-full opacity-10 transition-colors duration-1000 ${mode === 'work' ? 'bg-cyan-500' : 'bg-emerald-500'}`} />

      <div className="flex justify-between items-center w-full mb-8 relative z-10">
        <div className="flex flex-col">
          <h3 className="text-sm font-black uppercase tracking-widest text-white">Focus Hub</h3>
          <span className={`text-[10px] font-bold uppercase tracking-tighter mt-0.5 ${mode === 'work' ? 'text-cyan-400' : 'text-emerald-400'}`}>
            {mode === 'work' ? 'Deep Work' : 'Refuel Break'}
          </span>
        </div>
        <button 
          onClick={() => setShowSettings(!showSettings)}
          className={`p-2 rounded-xl transition-all ${showSettings ? 'bg-white/10 text-white shadow-inner shadow-black/20' : 'text-slate-500 hover:text-white'}`}
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0a1.532 1.532 0 01-2.286.948c-1.372-.836-2.942.734-2.106 2.106.54.886.061 2.042-.947 2.287-1.561.379-1.561 2.6 0 2.978a1.532 1.532 0 01.947 2.287c-.836 1.372.734 2.942 2.106 2.106a1.532 1.532 0 012.287.947c.379 1.561 2.6 1.561 2.978 0a1.533 1.533 0 012.287-.947c1.372.836 2.942-.734 2.106-2.106a1.533 1.533 0 01.947-2.287c1.561-.379 1.561-2.6 0-2.978a1.532 1.532 0 01-.947-2.287c.836-1.372-.734-2.942-2.106-2.106a1.532 1.532 0 01-2.287-.947zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
          </svg>
        </button>
      </div>

      {showSettings ? (
        <div className="w-full space-y-8 py-4 animate-reveal">
          <div className="space-y-6">
            <div className="space-y-3">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Work Cycle (Minutes)</span>
              <div className="flex items-center justify-between bg-black/40 p-2 rounded-2xl border border-white/5">
                <button onClick={() => adjustMinutes('work', -5)} className="w-10 h-10 rounded-xl bg-slate-800 text-white hover:bg-slate-700 transition-colors shadow-lg active:scale-95 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" /></svg>
                </button>
                <span className="text-2xl font-black font-mono-tech text-white w-12 text-center">{workMinutes}</span>
                <button onClick={() => adjustMinutes('work', 5)} className="w-10 h-10 rounded-xl bg-slate-800 text-white hover:bg-slate-700 transition-colors shadow-lg active:scale-95 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011-1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>
                </button>
              </div>
            </div>
            <div className="space-y-3">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Break Duration (Minutes)</span>
              <div className="flex items-center justify-between bg-black/40 p-2 rounded-2xl border border-white/5">
                <button onClick={() => adjustMinutes('break', -1)} className="w-10 h-10 rounded-xl bg-slate-800 text-white hover:bg-slate-700 transition-colors shadow-lg active:scale-95 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" /></svg>
                </button>
                <span className="text-2xl font-black font-mono-tech text-white w-12 text-center">{breakMinutes}</span>
                <button onClick={() => adjustMinutes('break', 1)} className="w-10 h-10 rounded-xl bg-slate-800 text-white hover:bg-slate-700 transition-colors shadow-lg active:scale-95 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 3a1 1 0 011-1v5h5a1 1 0 110 2h-5v5a1 1 0 11-2 0v-5H4a1 1 0 110-2h5V4a1 1 0 011-1z" clipRule="evenodd" /></svg>
                </button>
              </div>
            </div>
          </div>
          <button 
            onClick={() => setShowSettings(false)}
            className="w-full py-4 bg-cyan-600/10 text-cyan-400 border border-cyan-500/20 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-cyan-600 hover:text-white transition-all shadow-xl shadow-cyan-950/20"
          >
            Save Settings
          </button>
        </div>
      ) : (
        <div className="flex flex-col items-center py-6 w-full animate-reveal flex-1">
          <div className="relative mb-8 p-4">
            <svg 
              viewBox="0 0 210 210" 
              className="w-64 h-64 -rotate-90 drop-shadow-[0_0_15px_rgba(0,0,0,0.5)]"
            >
              <defs>
                <filter id="glow" x="-20%" y="-20%" width="140%" height="140%">
                  <feGaussianBlur stdDeviation="3.5" result="blur" />
                  <feComposite in="SourceGraphic" in2="blur" operator="over" />
                </filter>
              </defs>

              {/* Background Path (Sunken Track) */}
              <circle 
                cx="105" cy="105" r={normalizedRadius} 
                strokeWidth={strokeWidth} 
                className="fill-none stroke-slate-900/80" 
              />

              {/* Main Progress Bar */}
              <circle 
                cx="105" cy="105" r={normalizedRadius} 
                strokeWidth={strokeWidth} 
                strokeDasharray={circumference}
                strokeDashoffset={strokeDashoffset}
                strokeLinecap="round"
                filter="url(#glow)"
                className={`fill-none transition-all duration-1000 ease-linear ${
                  mode === 'work' ? 'stroke-cyan-500' : 'stroke-emerald-500'
                }`}
              />

              {/* Outer Pulsing Indicator */}
              {isActive && (
                <circle 
                  cx="105" cy="105" r={normalizedRadius + 5} 
                  strokeWidth="1" 
                  className={`fill-none animate-pulse opacity-20 ${
                    mode === 'work' ? 'stroke-cyan-400' : 'stroke-emerald-400'
                  }`} 
                />
              )}
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-6xl font-black font-mono-tech text-white tracking-tighter drop-shadow-[0_0_20px_rgba(255,255,255,0.1)]">{formatTime(timeLeft)}</span>
              <span className={`text-[10px] font-black uppercase tracking-[0.3em] mt-3 ${mode === 'work' ? 'text-cyan-400' : 'text-emerald-400'}`}>
                {mode}ING
              </span>
            </div>
          </div>

          <div className="flex items-center gap-8 mb-12">
            <button 
              onClick={resetTimer}
              className="w-12 h-12 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center text-slate-500 hover:text-white transition-all active:scale-95 group"
              title="Reset Timer"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 group-hover:rotate-[-45deg] transition-transform" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a7.002 7.002 0 0111.601 2.566 1 1 0 11-1.885.666A5.002 5.002 0 005.999 7H9a1 1 0 110 2H4a1 1 0 01-1-1V3a1 1 0 011-1zm.008 9.057a1 1 0 011.276.61A5.002 5.002 0 0014.001 13H11a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0v-2.101a7.002 7.002 0 01-1.392-2.348 1 1 0 111.885-.666 5.002 5.002 0 005.999-1.935H11z" clipRule="evenodd" />
              </svg>
            </button>
            <button 
              onClick={toggleTimer}
              className={`w-24 h-24 rounded-[2.5rem] flex items-center justify-center text-white shadow-2xl transition-all active:scale-90 ${isActive ? 'bg-slate-800' : mode === 'work' ? 'bg-cyan-600 shadow-cyan-900/30' : 'bg-emerald-600 shadow-emerald-900/30'}`}
            >
              {isActive ? (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 ml-1.5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                </svg>
              )}
            </button>
            <div className="w-12 h-12" />
          </div>

          <div className="w-full bg-slate-950/40 rounded-[2rem] p-6 border border-white/5 mt-auto">
            <div className="flex items-center justify-between mb-6">
              <div className="flex flex-col overflow-hidden max-w-[150px]">
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Curated Flow</span>
                <span className="text-xs font-bold text-slate-200 mt-1 truncate">{activePlaylist.icon} {currentTrack.name}</span>
              </div>
              <div className="flex items-center gap-3">
                <button onClick={prevTrack} className="text-slate-500 hover:text-white transition-colors active:scale-90">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M8.445 14.832A1 1 0 0010 14v-2.798l5.445 3.63A1 1 0 0017 14V6a1 1 0 00-1.555-.832L10 8.798V6a1 1 0 00-1.555-.832l-6 4a1 1 0 000 1.664l6 4z" /></svg>
                </button>
                <button 
                  onClick={toggleMusic}
                  className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shadow-xl ${isMusicPlaying ? 'bg-cyan-500 text-white shadow-cyan-900/20' : 'bg-white/5 text-slate-400 hover:text-white'}`}
                >
                  {isMusicPlaying ? (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                  ) : (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 ml-0.5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                  )}
                </button>
                <button onClick={nextTrack} className="text-slate-500 hover:text-white transition-colors active:scale-90">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M4.555 5.168A1 1 0 003 6v8a1 1 0 001.555.832L10 11.202V14a1 1 0 001.555.832l6-4a1 1 0 000-1.664l-6-4A1 1 0 0010 6v2.798l-5.445-3.63z" /></svg>
                </button>
              </div>
            </div>

            <div className="grid grid-cols-4 gap-2 mb-6">
              {PLAYLISTS.map(p => (
                <button 
                  key={p.id}
                  onClick={() => selectPlaylist(p.id)}
                  className={`flex flex-col items-center gap-1.5 p-3 rounded-2xl border transition-all ${activePlaylistId === p.id ? 'bg-cyan-500/10 border-cyan-500/40 shadow-inner' : 'bg-black/20 border-white/5 hover:border-white/10 hover:bg-black/40'}`}
                >
                  <span className="text-xl">{p.icon}</span>
                  <span className={`text-[8px] font-black uppercase tracking-tighter ${activePlaylistId === p.id ? 'text-cyan-400' : 'text-slate-600'}`}>{p.label.split(' ')[0]}</span>
                </button>
              ))}
            </div>

            <div className="flex items-center gap-4 px-2">
              <div className="text-slate-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.987 3.987 0 0013 10a3.987 3.987 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" /></svg>
              </div>
              <input 
                type="range" 
                min="0" 
                max="1" 
                step="0.01" 
                value={volume}
                onChange={(e) => setVolume(parseFloat(e.target.value))}
                className="flex-1 h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-cyan-500 hover:accent-cyan-400"
              />
            </div>
            {audioError && <p className="text-[9px] text-red-400 mt-4 text-center uppercase font-black tracking-widest animate-shake">{audioError}</p>}
          </div>
        </div>
      )}

      <audio 
        ref={audioRef} 
        src={currentTrack.url}
        onEnded={nextTrack}
        loop={false}
      />
    </div>
  );
};

