                </svg>
              )}
            </button>
            <div className="w-10 md:w-12 h-10 md:h-12" />
          </div>

          <div className="w-full bg-slate-950/40 rounded-[1.8rem] md:rounded-[2rem] p-4 md:p-6 border border-white/5 mt-auto">
            <div className="flex items-center justify-between mb-4 md:mb-6 gap-2">
              <div className="flex flex-col overflow-hidden flex-1">
                <span className="text-[8px] md:text-[10px] font-black uppercase tracking-widest text-slate-500">Curated Flow</span>
                <span className="text-[10px] md:text-xs font-bold text-slate-200 mt-1 truncate">{activePlaylist.icon} {currentTrack.name}</span>
              </div>
              <div className="flex items-center gap-2 md:gap-3 shrink-0">
                <button onClick={prevTrack} className="text-slate-500 hover:text-white active:scale-90">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 md:h-5 md:w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M8.445 14.832A1 1 0 0010 14v-2.798l5.445 3.63A1 1 0 0017 14V6a1 1 0 00-1.555-.832L10 8.798V6a1 1 0 00-1.555-.832l-6 4a1 1 0 000 1.664l6 4z" /></svg>
                </button>
                <button 
                  onClick={toggleMusic}
                  className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center transition-all ${isMusicPlaying ? 'bg-cyan-500 text-white' : 'bg-white/5 text-slate-400'}`}
                >
                  {isMusicPlaying ? (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 md:h-5 md:w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                  ) : (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 md:h-5 md:w-5 ml-0.5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                  )}
                </button>
                <button onClick={nextTrack} className="text-slate-500 hover:text-white active:scale-90">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 md:h-5 md:w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M4.555 5.168A1 1 0 003 6v8a1 1 0 001.555.832L10 11.202V14a1 1 0 001.555.832l6-4a1 1 0 000-1.664l-6-4A1 1 0 0010 6v2.798l-5.445-3.63z" /></svg>
                </button>
              </div>
            </div>

            <div className="grid grid-cols-4 gap-1.5 md:gap-2 mb-4 md:mb-6">
              {PLAYLISTS.map(p => (
                <button 
                  key={p.id}
                  onClick={() => selectPlaylist(p.id)}
                  className={`flex flex-col items-center gap-1 p-2 md:p-3 rounded-xl md:rounded-2xl border transition-all ${activePlaylistId === p.id ? 'bg-cyan-500/10 border-cyan-500/40 shadow-inner' : 'bg-black/20 border-white/5 hover:bg-black/40'}`}
                >
                  <span className="text-lg md:text-xl">{p.icon}</span>
                  <span className={`text-[7px] md:text-[8px] font-black uppercase tracking-tighter ${activePlaylistId === p.id ? 'text-cyan-400' : 'text-slate-600'}`}>{p.label.split(' ')[0]}</span>
                </button>
              ))}
            </div>

            <div className="flex items-center gap-3 md:gap-4 px-1 md:px-2">
              <div className="text-slate-600 shrink-0">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 md:h-3.5 md:w-3.5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.987 3.987 0 0013 10a3.987 3.987 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" /></svg>
              </div>
              <input 
                type="range" 
                min="0" 
                max="1" 
                step="0.01" 
                value={volume}
                onChange={(e) => setVolume(parseFloat(e.target.value))}
                className="flex-1 h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-cyan-500"
              />
            </div>
          </div>
        </div>
      )}

      <audio ref={audioRef} src={currentTrack.url} onEnded={nextTrack} loop={false} />
    </div>
  );
};

