import React, { useState, useEffect } from 'react';
import { Resource } from '../types';

const CATEGORIES: Resource['category'][] = ['YouTube', 'PDF', 'Portal', 'Notes', 'Other'];

const CATEGORY_ICONS: Record<Resource['category'], string> = {
  YouTube: '📹',
  PDF: '📄',
  Portal: '🌐',
  Notes: '📝',
  Other: '🔗'
};

const ResourceVault: React.FC = () => {
  const [resources, setResources] = useState<Resource[]>(() => {
    const saved = localStorage.getItem('al_2026_resources');
    if (saved) return JSON.parse(saved);
    return [
      { id: '1', title: 'Department of Examinations (Official)', url: 'https://www.doenets.lk', category: 'Portal' },
      { id: '2', title: 'Physics Past Papers (2010-2024)', url: 'https://example.com/physics-archive', category: 'PDF' },
      { id: '3', title: 'Organic Chemistry: Mechanism Guide', url: 'https://youtube.com/watch?v=example1', category: 'YouTube' },
      { id: '4', title: 'Short Notes: Combined Maths Vectors', url: '#', category: 'Notes' }
    ];
  });

  const [showAdd, setShowAdd] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newUrl, setNewUrl] = useState('');
  const [newCategory, setNewCategory] = useState<Resource['category']>('YouTube');
  const [activeFilter, setActiveFilter] = useState<Resource['category'] | 'All'>('All');

  useEffect(() => {
    localStorage.setItem('al_2026_resources', JSON.stringify(resources));
  }, [resources]);

  const addResource = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTitle || !newUrl) return;

    const res: Resource = {
      id: crypto.randomUUID(),
      title: newTitle,
      url: newUrl.startsWith('http') || newUrl.startsWith('#') ? newUrl : `https://${newUrl}`,
      category: newCategory
    };

    setResources([res, ...resources]);
    setNewTitle('');
    setNewUrl('');
    setNewCategory('YouTube');
    setShowAdd(false);
  };

  const deleteResource = (id: string) => {
    setResources(resources.filter(r => r.id !== id));
  };

  const filteredResources = resources.filter(res => 
    activeFilter === 'All' ? true : res.category === activeFilter
  );

  return (
    <div className="glass-card rounded-[2.5rem] p-6 md:p-8 border-blue-500/10 w-full flex flex-col h-full min-h-[500px] md:min-h-[600px] relative overflow-hidden">
      <div className="absolute -top-10 -left-10 w-40 h-40 bg-blue-500/5 blur-3xl rounded-full" />

      <div className="flex justify-between items-center mb-6 md:mb-8 relative z-10">
        <div>
          <h3 className="text-lg md:text-xl font-black font-outfit flex items-center gap-2 md:gap-3 text-white">
            <span className="text-xl md:text-2xl">📑</span> Resource Vault
          </h3>
          <p className="text-[8px] md:text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Academic digital library</p>
        </div>
        <button 
          onClick={() => setShowAdd(!showAdd)}
          className={`px-3 md:px-5 py-2 md:py-2.5 rounded-xl md:rounded-2xl text-[8px] md:text-[10px] font-black uppercase tracking-widest transition-all duration-300 ${
            showAdd ? 'bg-red-500/10 text-red-400' : 'bg-blue-600 text-white shadow-xl'
          }`}
        >
          {showAdd ? 'Discard' : 'New Link'}
        </button>
      </div>

      {showAdd && (
        <form onSubmit={addResource} className="mb-6 md:mb-8 space-y-4 md:space-y-5 bg-slate-950/60 p-4 md:p-6 rounded-[1.8rem] md:rounded-[2rem] border border-white/5 animate-reveal relative z-10">
          <div className="space-y-4">
            <div className="space-y-1 md:space-y-2">
              <label className="text-[8px] md:text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Display Title</label>
              <input
                type="text"
                placeholder="e.g., Pure Maths Discussion"
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
                className="w-full bg-slate-900 border border-white/5 rounded-xl md:rounded-2xl px-4 py-2.5 md:py-3.5 text-xs md:text-sm text-white focus:outline-none"
              />
            </div>

            <div className="space-y-1 md:space-y-2">
              <label className="text-[8px] md:text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">URL or Source Path</label>
              <input
                type="text"
                placeholder="https://youtube.com/..."
                value={newUrl}
                onChange={(e) => setNewUrl(e.target.value)}
                className="w-full bg-slate-900 border border-white/5 rounded-xl md:rounded-2xl px-4 py-2.5 md:py-3.5 text-xs md:text-sm text-white focus:outline-none"
              />
            </div>

            <div className="space-y-2 md:space-y-3">
              <label className="text-[8px] md:text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Category</label>
              <div className="grid grid-cols-3 sm:grid-cols-5 gap-1.5 md:gap-2">
                {CATEGORIES.map(cat => (
                  <button
                    key={cat}
                    type="button"
                    onClick={() => setNewCategory(cat)}
                    className={`py-2 px-1 rounded-lg md:rounded-xl text-[7px] md:text-[9px] font-black uppercase border transition-all flex flex-col items-center gap-1 ${
                      newCategory === cat 
                        ? 'bg-blue-600 border-blue-500 text-white' 
                        : 'bg-slate-900 border-white/5 text-slate-500'
                    }`}
                  >
                    <span className="text-sm md:text-base">{CATEGORY_ICONS[cat]}</span>
                    <span className="hidden sm:inline">{cat}</span>
                  </button>
                ))}
              </div>
            </div>
          </div>

          <button type="submit" className="w-full bg-indigo-600 py-3 md:py-4 rounded-xl md:rounded-2xl text-[8px] md:text-[10px] font-black uppercase tracking-widest text-white shadow-xl mt-2">
            Add to My Vault
          </button>
        </form>
      )}

      <div className="flex items-center gap-2 mb-6 md:mb-8 overflow-x-auto pb-2 custom-scrollbar relative z-10 no-scrollbar">
        <button
          onClick={() => setActiveFilter('All')}
          className={`shrink-0 px-3 md:px-5 py-1.5 md:py-2.5 rounded-xl md:rounded-2xl text-[8px] md:text-[10px] font-black uppercase transition-all border ${
            activeFilter === 'All' ? 'bg-blue-600/10 border-blue-500/40 text-blue-400' : 'bg-slate-900/40 border-white/5 text-slate-500'
          }`}
        >
          All
        </button>
        {CATEGORIES.map(cat => (
          <button
            key={cat}
            onClick={() => setActiveFilter(cat)}
            className={`shrink-0 px-3 md:px-5 py-1.5 md:py-2.5 rounded-xl md:rounded-2xl text-[8px] md:text-[10px] font-black uppercase transition-all border flex items-center gap-1.5 ${
              activeFilter === cat ? 'bg-blue-600/10 border-blue-500/40 text-blue-400' : 'bg-slate-900/40 border-white/5 text-slate-500'
            }`}
          >
            <span>{CATEGORY_ICONS[cat]}</span>
            {cat}
          </button>
        ))}
      </div>

      <div className="space-y-2 md:space-y-3 flex-1 overflow-y-auto pr-1 md:pr-2 custom-scrollbar relative z-10">
        {filteredResources.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 md:py-24 text-center">
            <div className="w-16 h-16 md:w-20 md:h-20 rounded-[1.5rem] md:rounded-[2rem] bg-slate-900/50 flex items-center justify-center text-3xl md:text-4xl mb-4 md:mb-6 border border-white/5 grayscale">📂</div>
            <p className="text-slate-400 text-xs md:text-sm font-bold uppercase tracking-widest">Vault Empty</p>
          </div>
        ) : (
          filteredResources.map(res => (
            <div key={res.id} className="flex items-center gap-3 md:gap-4 p-3 md:p-4 rounded-[1.5rem] md:rounded-[2rem] bg-slate-950/40 border border-white/5 hover:border-white/10 transition-all group animate-reveal">
              <div className="w-10 h-10 md:w-12 md:h-12 shrink-0 rounded-xl md:rounded-2xl bg-slate-900 flex items-center justify-center text-lg md:text-xl border border-white/5">
                {CATEGORY_ICONS[res.category]}
              </div>

              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-0.5 md:mb-1">
                   <span className="text-[7px] md:text-[8px] font-black uppercase tracking-widest px-1.5 md:py-0.5 rounded-full bg-blue-500/10 text-blue-400 border border-blue-500/20">
                    {res.category}
                  </span>
                </div>
                <a href={res.url} target="_blank" rel="noopener noreferrer" className="text-xs md:text-sm font-bold text-slate-200 hover:text-blue-400 transition-colors block truncate pr-4">
                  {res.title}
                </a>
              </div>

              <div className="flex items-center gap-1 md:gap-2 opacity-100 sm:opacity-0 group-hover:opacity-100 transition-all">
                <button onClick={() => deleteResource(res.id)} className="p-2 md:p-2.5 rounded-lg md:rounded-xl bg-red-500/5 text-slate-600 hover:text-red-400 border border-transparent hover:border-red-500/20 transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5 md:h-4 md:w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default ResourceVault;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
