import React, { useMemo } from 'react';
import { Subject, Goal } from '../types';

interface OverallStatsProps {
  subjects: Subject[];
  goals: Goal[];
}

const OverallStats: React.FC<OverallStatsProps> = ({ subjects, goals }) => {
  const stats = useMemo(() => {
    const totalUnits = subjects.reduce((acc, s) => acc + s.units.length, 0);
    const completedUnits = subjects.reduce((acc, s) => acc + s.units.filter(u => u.completed).length, 0);
    const overallProgress = totalUnits > 0 ? Math.round((completedUnits / totalUnits) * 100) : 0;

    const totalGoals = goals.length;
    const completedGoals = goals.filter(g => g.completed).length;
    const goalSuccessRate = totalGoals > 0 ? Math.round((completedGoals / totalGoals) * 100) : 0;

    const prioritizedSubjects = subjects.filter(s => s.isPrioritized);
    const priorityProgress = prioritizedSubjects.length > 0 
      ? Math.round(prioritizedSubjects.reduce((acc, s) => acc + s.progress, 0) / prioritizedSubjects.length)
      : 0;

    const sortedByProgress = [...subjects].sort((a, b) => b.progress - a.progress);
    const topSubject = sortedByProgress[0];
    const needFocusSubject = sortedByProgress[sortedByProgress.length - 1];

    const nextMilestone = Math.ceil((overallProgress + 0.1) / 10) * 10;
    const unitsToNextMilestone = Math.ceil(((nextMilestone / 100) * totalUnits) - completedUnits);

    // Consistency logic (simulated based on completed goals vs total units)
    const consistencyScore = Math.min(100, Math.round((goalSuccessRate * 0.6) + (overallProgress * 0.4)));

    return {
      totalUnits,
      completedUnits,
      overallProgress,
      totalGoals,
      completedGoals,
      goalSuccessRate,
      priorityProgress,
      topSubject,
      needFocusSubject,
      nextMilestone,
      unitsToNextMilestone,
      consistencyScore
    };
  }, [subjects, goals]);

  const ProgressRing = ({ percentage, label, color, glowColor, size = 160 }: { percentage: number, label: string, color: string, glowColor: string, size?: number }) => {
    const radius = size * 0.45;
    const stroke = size * 0.08;
    const normalizedRadius = radius - stroke;
    const circumference = normalizedRadius * 2 * Math.PI;
    const strokeDashoffset = circumference - (percentage / 100) * circumference;

    return (
      <div className="flex flex-col items-center group relative">
        <div className="relative" style={{ width: size, height: size }}>
          {/* Background Glow */}
          <div 
            className="absolute inset-0 rounded-full blur-[30px] opacity-20 transition-all duration-1000 group-hover:opacity-40" 
            style={{ backgroundColor: glowColor }}
          />

          <svg height={size} width={size} className="-rotate-90 relative z-10">
            <defs>
              <linearGradient id={`grad-${label}`} x1="0%" y1="0%" x2="100%" y2="100%">
                <stop offset="0%" stopColor={color} />
                <stop offset="100%" stopColor={glowColor} />
              </linearGradient>
            </defs>
            <circle
              stroke="rgba(255,255,255,0.03)"
              fill="transparent"
              strokeWidth={stroke}
              r={normalizedRadius}
              cx={size / 2}
              cy={size / 2}
            />
            <circle
              stroke={`url(#grad-${label})`}
              fill="transparent"
              strokeWidth={stroke}
              strokeDasharray={circumference + ' ' + circumference}
              style={{ strokeDashoffset, transition: 'stroke-dashoffset 1.5s cubic-bezier(0.4, 0, 0.2, 1)' }}
              strokeLinecap="round"
              r={normalizedRadius}
              cx={size / 2}
              cy={size / 2}
              className="drop-shadow-[0_0_12px_rgba(255,255,255,0.1)]"
            />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center flex-col z-20">
            <span className="text-3xl md:text-4xl font-black font-mono-tech text-white leading-none tracking-tighter">
              {percentage}<span className="text-sm opacity-50 ml-0.5">%</span>
            </span>
          </div>
        </div>
        <span className="mt-4 text-[10px] md:text-xs font-black uppercase tracking-[0.2em] text-slate-500 group-hover:text-blue-400 transition-colors">
          {label}
        </span>
      </div>
    );
  };

  const getMasteryLevel = (progress: number) => {
    if (progress >= 90) return { label: 'Grandmaster', color: 'text-amber-400', bg: 'bg-amber-400/10', border: 'border-amber-400/20' };
    if (progress >= 70) return { label: 'Expert', color: 'text-emerald-400', bg: 'bg-emerald-400/10', border: 'border-emerald-400/20' };
    if (progress >= 40) return { label: 'Intermediate', color: 'text-blue-400', bg: 'bg-blue-400/10', border: 'border-blue-400/20' };
    if (progress >= 10) return { label: 'Initiate', color: 'text-indigo-400', bg: 'bg-indigo-400/10', border: 'border-indigo-400/20' };
    return { label: 'Novice', color: 'text-slate-500', bg: 'bg-slate-500/10', border: 'border-slate-500/10' };
  };

  const criticalSubject = stats.needFocusSubject && stats.needFocusSubject.progress < 20 ? stats.needFocusSubject : null;

  return (
    <div className="space-y-8 md:space-y-12 animate-reveal pb-20">
      {/* Dynamic Alerts */}
      {criticalSubject && (
        <div className="glass-card rounded-2xl p-4 md:px-6 border-red-500/20 bg-red-500/5 flex items-center justify-between animate-pulse">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 rounded-xl bg-red-500/20 flex items-center justify-center text-red-500 text-xl">⚠️</div>
            <div>
              <p className="text-xs font-black uppercase tracking-widest text-red-400">Critical Priority Focus</p>
              <p className="text-sm font-bold text-white">Your mastery in {criticalSubject.name} is significantly below target benchmarks.</p>
            </div>
          </div>
          <div className="hidden md:block">
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-red-500/60">Urgent Attention Required</span>
          </div>
        </div>
      )}

      {/* Hero Stats Section */}
      <div className="glass-card rounded-[3rem] p-8 md:p-16 border-white/5 relative overflow-hidden shadow-2xl">
        <div className="absolute top-0 right-0 w-1/3 h-full bg-gradient-to-l from-blue-600/10 to-transparent pointer-events-none blur-[100px]" />
        <div className="absolute bottom-0 left-0 w-1/3 h-full bg-gradient-to-r from-emerald-600/5 to-transparent pointer-events-none blur-[100px]" />

        <div className="grid grid-cols-1 md:grid-cols-3 gap-12 md:gap-8 relative z-10">
          <ProgressRing percentage={stats.overallProgress} label="Total Mastery" color="#3b82f6" glowColor="#1d4ed8" size={180} />
          <ProgressRing percentage={stats.goalSuccessRate} label="Consistency" color="#10b981" glowColor="#065f46" size={180} />
          <ProgressRing percentage={stats.priorityProgress} label="Priority Edge" color="#f59e0b" glowColor="#92400e" size={180} />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left: Mastery Leaderboard */}
        <div className="lg:col-span-7 space-y-6">
          <div className="glass-card rounded-[2.5rem] p-8 md:p-10 border-white/5 h-full relative overflow-hidden">
             <div className="flex flex-col md:flex-row md:items-center justify-between mb-12 gap-4">
              <div>
                <h3 className="text-xl md:text-2xl font-black font-outfit text-white flex items-center gap-3">
                  <span className="p-2.5 bg-blue-500/10 rounded-2xl text-blue-400 text-lg">🎖️</span>
                  Mastery Tiers
                </h3>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Subject performance analysis</p>
              </div>
              <div className="px-5 py-2 rounded-2xl bg-slate-900/80 border border-white/10 flex items-center gap-4">
                <div className="flex flex-col">
                  <span className="text-[8px] font-black text-slate-500 uppercase tracking-tighter">Units Unlocked</span>
                  <span className="text-sm font-black text-white">{stats.completedUnits}<span className="opacity-20 mx-1">/</span>{stats.totalUnits}</span>
                </div>
                <div className="w-[1px] h-8 bg-white/5" />
                <div className="flex flex-col">
                  <span className="text-[8px] font-black text-slate-500 uppercase tracking-tighter">Active Subjects</span>
                  <span className="text-sm font-black text-white">{subjects.length}</span>
                </div>
              </div>
            </div>

            <div className="space-y-12">
              {subjects.map((subject, idx) => {
                const mastery = getMasteryLevel(subject.progress);
                return (
                  <div key={subject.id} className="group relative">
                    <div className="flex justify-between items-end mb-4">
                      <div className="flex items-center gap-4">
                         <div className="w-10 h-10 rounded-2xl bg-slate-950 flex items-center justify-center text-xs font-black font-mono-tech text-slate-700 border border-white/5 group-hover:border-blue-500/20 transition-all">
                          {idx + 1}
                        </div>
                        <div className="flex flex-col">
                          <h4 className="font-bold text-slate-200 group-hover:text-white transition-colors flex items-center gap-2">
                            {subject.name}
                            {subject.isPrioritized && <span className="text-amber-500 animate-pulse text-sm" title="Priority Focus">★</span>}
                          </h4>
                          <div className={`inline-flex items-center px-2 py-0.5 rounded-lg ${mastery.bg} ${mastery.color} ${mastery.border} text-[8px] font-black uppercase tracking-widest mt-1.5 w-fit border`}>
                            {mastery.label}
                          </div>
                        </div>
                      </div>
                      <div className="text-right flex flex-col items-end">
                        <span className="text-3xl font-black font-mono-tech text-white tracking-tighter leading-none">{subject.progress}%</span>
                        <div className="flex items-center gap-2 mt-2">
                           <div className="h-1 w-12 bg-slate-800 rounded-full overflow-hidden">
                             <div className="h-full bg-blue-500/40" style={{ width: `${(subject.units.filter(u => u.completed).length / subject.units.length) * 100}%` }} />
                           </div>
                           <span className="text-[9px] font-black text-slate-500 uppercase tracking-tighter">
                            {subject.units.filter(u => u.completed).length} UNITS
                          </span>
                        </div>
                      </div>
                    </div>

                    <div className="relative h-3 w-full bg-slate-950 rounded-full overflow-hidden border border-white/5 p-0.5 shadow-inner">
                      <div 
                        className={`h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_20px_rgba(59,130,246,0.3)] ${subject.color}`}
                        style={{ width: `${subject.progress}%`, transitionDelay: `${idx * 100}ms` }}
                      >
                         <div className="w-full h-full bg-white/10 animate-[pulse_2s_infinite]" />
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Right: Analytics Sidebar */}
        <div className="lg:col-span-5 space-y-6">
          <div className="glass-card rounded-[2.5rem] p-8 md:p-10 border-white/5 bg-slate-900/20 relative overflow-hidden">
            <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-8 flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-blue-500" /> Advanced Forecast
            </h4>

            <div className="space-y-6">
              {/* Milestone Tracker */}
              <div className="p-6 rounded-[2rem] bg-gradient-to-br from-blue-600/10 to-indigo-600/5 border border-blue-500/20 shadow-xl">
                <div className="flex justify-between items-start mb-6">
