    const remainingUnits = totalUnits - completedUnits;
    const estDaysToFinish = remainingUnits * 2.5; // Roughly 2.5 days per unit
    const completionDate = new Date();
    completionDate.setDate(completionDate.getDate() + estDaysToFinish);

