      totalUnits,
      completedUnits,
      overallProgress,
      totalGoals,
      completedGoals,
      goalSuccessRate,
      priorityProgress,
      topSubject,
      needFocusSubject,
      nextMilestone,
      unitsToNextMilestone,
      consistencyScore,
