            <p className="text-[11px] font-bold text-slate-300 mt-4 leading-relaxed">
              Unlock <span className="text-white">{stats.unitsToNextMilestone} more units</span> across your subjects to hit your next batch-wide benchmark.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default OverallStats;

import { GoogleGenAI, Type } from "@google/genai";
import { GeminiAdvice, ChatMessage } from "../types";

// Helper to initialize AI with latest key and handle missing key scenario
const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API key is missing. Ensure it is set in Vercel Environment Variables.");
  }
  return new GoogleGenAI({ apiKey });
};

export const getDailyAdvice = async (daysRemaining: number): Promise<GeminiAdvice> => {
  try {
    const ai = getAIClient();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Candidate has ${daysRemaining} days for Sri Lanka GCE A/L 2026. Provide short, practical study advice.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            category: { 
              type: Type.STRING,
              enum: ['motivation', 'study-tip', 'exam-strategy']
            }
          },
          required: ["title", "content", "category"]
        }
      },
    });

    const text = response.text?.trim();
    return text ? JSON.parse(text) : { title: "Stay Focus", content: "Keep moving forward.", category: "motivation" };
  } catch (error: any) {
    console.error("Advice Error:", error);
    return { title: "Resilience", content: "Consistency beats intensity. Keep going.", category: "motivation" };
  }
};

export const chatWithStudyBuddy = async (history: ChatMessage[], prompt: string): Promise<string> => {
  try {
    const ai = getAIClient();
    const chat = ai.chats.create({
      model: "gemini-3-flash-preview",
      config: {
        systemInstruction: "You are 'A-Level Buddy', a supportive AI for Sri Lankan A/L students (2026 Batch). Help with study plans and subject logic. Use local context (e.g., mention Tuition, Papers, DoENets). Keep it concise.",
      }
    });

    const result = await chat.sendMessage({ message: prompt });
    return result.text || "I'm listening, but my study circuits are a bit quiet right now.";
  } catch (error: any) {
    return "I'm having trouble connecting to my study notes. Please check your internet.";
  }
};

export interface ExamNews {
  text: string;
  sources: { uri: string; title: string }[];
  isConfirmed: boolean;
  error?: string;
}

export const fetchLatestExamNews = async (): Promise<ExamNews> => {
  try {
    const ai = getAIClient();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Latest official news regarding Sri Lanka GCE A/L 2026 exam dates and schedule from doenets.lk",
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        uri: chunk.web?.uri,
        title: chunk.web?.title
      }))
      .filter((s: any) => s.uri && s.title) || [];

    const text = response.text || "Checking official sources...";
    const isConfirmed = text.toLowerCase().includes("confirmed") || text.includes("2026");

    return {
      text: text,
      sources: sources.slice(0, 4),
      isConfirmed
    };
  } catch (error: any) {
    return {
      text: "Unable to verify live news at this moment.",
      sources: [{ uri: "https://www.doenets.lk", title: "Official Exam Portal" }],
      isConfirmed: false
    };
  }
};

import { defineConfig, loadEnv } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig(({ mode }) => {
  // Load env file based on `mode` in the current working directory.
  // Set the third parameter to '' to load all envs regardless of the `VITE_` prefix.
  // Fix: Cast process to any to resolve 'Property cwd does not exist on type Process' error
  const env = loadEnv(mode, (process as any).cwd(), '');

  return {
    plugins: [react()],
    define: {
      // Mapping API_KEY so process.env.API_KEY works in the browser
      // Fix: Cast process to any to safely access env variables in the config context
      'process.env.API_KEY': JSON.stringify(env.API_KEY || (process as any).env.API_KEY)
    },
    server: {
      port: 3000,
      open: true
    },
    build: {
      outDir: 'dist',
      sourcemap: true,
      rollupOptions: {
        output: {
          manualChunks: {
            vendor: ['react', 'react-dom'],
            genai: ['@google/genai']
          }
        }
      }
    }
  };
});
